DROP TABLE IF EXISTS `base_hexagram`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `base_hexagram` (
  `id` tinyint unsigned NOT NULL COMMENT '卦序 1-64',
  `name` varchar(10) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '卦名（如：乾为天）',
  `name_short` varchar(4) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '卦名简称（如：乾）',
  `upper_gua` char(1) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '上卦（乾坎艮震巽离坤兑）',
  `lower_gua` char(1) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '下卦',
  `palace` char(1) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '宫属（八宫之一）',
  `palace_nature` char(1) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '卦宫五行（金木水火土）',
  `position_in_palace` tinyint NOT NULL COMMENT '宫中位置 1-8',
  `hexagram_type` enum('首卦','一世','二世','三世','四世','五世','游魂','归魂') COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '卦类型',
  `sequence_code` char(3) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '卦序编码（如：乾1）',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_name` (`name`),
  KEY `idx_palace` (`palace`),
  KEY `idx_upper_lower` (`upper_gua`,`lower_gua`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='卦象基础信息表（静态）';
