INSERT INTO `base_hexagram_text` VALUES (1,1,'卦辞',NULL,'乾：元亨利贞。','乾卦象征天，具有元始、亨通、和谐、贞正四种美德。'),(2,1,'大象',NULL,'天行健，君子以自强不息。','天道运行刚健有力，君子应当效法天道，自强不息，永不停止。'),(3,1,'爻辞',1,'初九：潜龙勿用。','龙潜伏在水中，暂时不宜有所作为。比喻君子在时机未到时应当韬光养晦。'),(4,1,'爻辞',2,'九二：见龙在田，利见大人。','龙出现在田野上，利于拜见大人物。比喻君子崭露头角，可以有所作为。'),(5,1,'爻辞',3,'九三：君子终日乾乾，夕惕若厉，无咎。','君子整天勤勉努力，到了晚上还保持警惕，虽有危险但无灾祸。'),(6,1,'爻辞',4,'九四：或跃在渊，无咎。','龙或跃起或潜入深渊，没有灾祸。比喻进退有度，审时度势。'),(7,1,'爻辞',5,'九五：飞龙在天，利见大人。','龙飞翔在天空，利于拜见大人物。比喻君子功成名就，大展宏图。'),(8,1,'爻辞',6,'上九：亢龙有悔。','龙飞得太高会有悔恨。比喻物极必反，盛极而衰。'),(9,2,'卦辞',NULL,'坤：元亨，利牝马之贞。君子有攸往，先迷后得主，利西南得朋，东北丧朋。安贞吉。','坤卦象征地，具有元始、亨通的美德，利于像母马那样柔顺贞正。君子有所往，先迷失后得到主人，西南方得到朋友，东北方失去朋友。安于正道则吉祥。'),(10,2,'大象',NULL,'地势坤，君子以厚德载物。','大地的形势是顺承的，君子应当效法大地，以深厚的德行承载万物。'),(11,2,'爻辞',1,'初六：履霜，坚冰至。','踩到霜，坚冰将要到来。比喻见微知著，防患于未然。'),(12,2,'爻辞',2,'六二：直方大，不习无不利。','正直、方正、宏大，不用学习也无所不利。比喻坤德自然，无为而成。'),(13,2,'爻辞',3,'六三：含章可贞，或从王事，无成有终。','蕴含美德可以守正，或者从事王事，虽无功成但有善终。'),(14,2,'爻辞',4,'六四：括囊，无咎无誉。','扎紧口袋，没有灾祸也没有荣誉。比喻谨慎收敛，明哲保身。'),(15,2,'爻辞',5,'六五：黄裳，元吉。','黄色的下裳，大吉大利。黄色居中，裳在下，比喻居中守正，谦逊处下。'),(16,2,'爻辞',6,'上六：龙战于野，其血玄黄。','龙在野外争斗，流出青黄色的血。比喻阴盛阳衰，两败俱伤。'),(17,3,'卦辞',NULL,'屯：元亨利贞，勿用有攸往，利建侯。','屯卦象征初生的艰难，具有元始、亨通、和谐、贞正四德，不宜有所往，利于建立诸侯。'),(18,3,'大象',NULL,'云雷屯，君子以经纶。','云雷交加象征屯难，君子应当经营治理，筹划大业。'),(19,3,'爻辞',1,'初九：磐桓，利居贞，利建侯。','徘徊不前，利于安居守正，利于建立诸侯。'),(20,3,'爻辞',2,'六二：屯如邅如，乘马班如。匪寇婚媾，女子贞不字，十年乃字。','艰难困顿，骑马徘徊。不是强盗而是求婚者，女子守正不嫁，十年后才出嫁。'),(21,3,'爻辞',3,'六三：即鹿无虞，惟入于林中，君子几不如舍，往吝。','追逐野鹿没有向导，只能进入林中，君子见机不如放弃，前往有悔。'),(22,3,'爻辞',4,'六四：乘马班如，求婚媾，往吉，无不利。','骑马徘徊，求婚姻，前往吉祥，无所不利。'),(23,3,'爻辞',5,'九五：屯其膏，小贞吉，大贞凶。','积蓄恩泽，小事守正吉祥，大事守正凶险。'),(24,3,'爻辞',6,'上六：乘马班如，泣血涟如。','骑马徘徊，泪流如血。比喻困顿至极，悲伤不已。'),(25,4,'卦辞',NULL,'蒙：亨。匪我求童蒙，童蒙求我。初筮告，再三渎，渎则不告。利贞。','蒙卦象征蒙昧，亨通。不是我求教于蒙昧的童子，而是童子来求教于我。初次占筮告诉他，再三占筮是亵渎，亵渎就不告诉。利于守正。'),(26,4,'大象',NULL,'山下出泉，蒙；君子以果行育德。','山下涌出泉水象征蒙昧，君子应当果断行动，培育德行。'),(27,4,'爻辞',1,'初六：发蒙，利用刑人，用说桎梏，以往吝。','启发蒙昧，利于用刑罚教育人，解除桎梏，前往有悔。'),(28,4,'爻辞',2,'九二：包蒙吉，纳妇吉，子克家。','包容蒙昧吉祥，娶妻吉祥，儿子能治家。'),(29,4,'爻辞',3,'六三：勿用取女，见金夫，不有躬，无攸利。','不要娶这样的女子，她见到有钱人就失身，没有什么好处。'),(30,4,'爻辞',4,'六四：困蒙，吝。','困于蒙昧，有悔。'),(31,4,'爻辞',5,'六五：童蒙，吉。','童子蒙昧，吉祥。比喻虚心求教，谦逊好学。'),(32,4,'爻辞',6,'上九：击蒙，不利为寇，利御寇。','击打蒙昧，不利于做强盗，利于防御强盗。'),(33,5,'卦辞',NULL,'需：有孚，光亨，贞吉。利涉大川。','需卦象征等待，有诚信，光明亨通，守正吉祥。利于渡过大河。'),(34,5,'大象',NULL,'云上于天，需；君子以饮食宴乐。','云气上升于天象征等待，君子应当饮食宴乐，安心等待。'),(35,5,'爻辞',1,'初九：需于郊，利用恒，无咎。','在郊外等待，利于持之以恒，没有灾祸。'),(36,5,'爻辞',2,'九二：需于沙，小有言，终吉。','在沙滩上等待，稍有口舌，最终吉祥。'),(37,5,'爻辞',3,'九三：需于泥，致寇至。','在泥泞中等待，招致盗寇到来。'),(38,5,'爻辞',4,'六四：需于血，出自穴。','在血泊中等待，从洞穴中出来。比喻处境危险，需要脱身。'),(39,5,'爻辞',5,'九五：需于酒食，贞吉。','在酒食中等待，守正吉祥。'),(40,5,'爻辞',6,'上六：入于穴，有不速之客三人来，敬之终吉。','进入洞穴，有三位不速之客到来，恭敬对待最终吉祥。'),(41,6,'卦辞',NULL,'讼：有孚窒惕，中吉，终凶。利见大人，不利涉大川。','讼卦象征争讼，有诚信但受阻而恐惧，中途吉祥，最终凶险。利于拜见大人，不利于渡过大河。'),(42,6,'大象',NULL,'天与水违行，讼；君子以作事谋始。','天与水背道而行象征争讼，君子应当做事谋划于开始。'),(43,6,'爻辞',1,'初六：不永所事，小有言，终吉。','不长久从事争讼，稍有口舌，最终吉祥。'),(44,6,'爻辞',2,'九二：不克讼，归而逋，其邑人三百户，无眚。','争讼不胜，回去逃避，他的邑人三百户，没有灾祸。'),(45,6,'爻辞',3,'六三：食旧德，贞厉，终吉。或从王事，无成。','享用祖先的德泽，守正有危险，最终吉祥。或者从事王事，没有功成。'),(46,6,'爻辞',4,'九四：不克讼，复即命，渝安贞，吉。','争讼不胜，回来顺从天命，改变而安于正道，吉祥。'),(47,6,'爻辞',5,'九五：讼，元吉。','争讼，大吉大利。'),(48,6,'爻辞',6,'上九：或锡之鞶带，终朝三褫之。','或许赐给他大带，一天之内三次被剥夺。比喻得而复失。'),(49,7,'卦辞',NULL,'师：贞，丈人吉，无咎。','师卦象征军队，守正，德高望重的长者吉祥，没有灾祸。'),(50,7,'大象',NULL,'地中有水，师；君子以容民畜众。','地中有水象征军队，君子应当容纳民众，畜养众人。'),(51,7,'爻辞',1,'初六：师出以律，否臧凶。','军队出征要有纪律，否则不论好坏都凶险。'),(52,7,'爻辞',2,'九二：在师中，吉无咎，王三锡命。','在军队中，吉祥没有灾祸，君王三次赐命。'),(53,7,'爻辞',3,'六三：师或舆尸，凶。','军队或许载着尸体回来，凶险。'),(54,7,'爻辞',4,'六四：师左次，无咎。','军队向左驻扎，没有灾祸。'),(55,7,'爻辞',5,'六五：田有禽，利执言，无咎。长子帅师，弟子舆尸，贞凶。','田中有禽兽，利于捕获，没有灾祸。长子统帅军队，小儿子载尸而归，守正凶险。'),(56,7,'爻辞',6,'上六：大君有命，开国承家，小人勿用。','大君有命令，开创国家承继家业，不要任用小人。'),(57,8,'卦辞',NULL,'比：吉。原筮元永贞，无咎。不宁方来，后夫凶。','比卦象征亲近，吉祥。再次占筮，元始永久守正，没有灾祸。不安宁的人来归附，后来的人凶险。'),(58,8,'大象',NULL,'地上有水，比；先王以建万国，亲诸侯。','地上有水象征亲近，先王因此建立万国，亲近诸侯。'),(59,8,'爻辞',1,'初六：有孚比之，无咎。有孚盈缶，终来有它，吉。','有诚信地亲近，没有灾祸。诚信充满瓦罐，最终会有意外收获，吉祥。'),(60,8,'爻辞',2,'六二：比之自内，贞吉。','从内部亲近，守正吉祥。'),(61,8,'爻辞',3,'六三：比之匪人。','亲近不正当的人。'),(62,8,'爻辞',4,'六四：外比之，贞吉。','从外部亲近，守正吉祥。'),(63,8,'爻辞',5,'九五：显比，王用三驱，失前禽。邑人不诫，吉。','光明正大地亲近，君王用三面围猎，放走前面的禽兽。邑人不用告诫，吉祥。'),(64,8,'爻辞',6,'上六：比之无首，凶。','亲近没有首领，凶险。'),(65,9,'卦辞',NULL,'小畜：亨。密云不雨，自我西郊。','小畜卦象征小有积蓄，亨通。密云不下雨，从我的西郊飘来。'),(66,9,'大象',NULL,'风行天上，小畜；君子以懿文德。','风行于天上象征小有积蓄，君子应当修养文德。'),(67,9,'爻辞',1,'初九：复自道，何其咎，吉。','从原路返回，有什么灾祸呢，吉祥。'),(68,9,'爻辞',2,'九二：牵复，吉。','被牵引而返回，吉祥。'),(69,9,'爻辞',3,'九三：舆说辐，夫妻反目。','车轮脱落辐条，夫妻反目。'),(70,9,'爻辞',4,'六四：有孚，血去惕出，无咎。','有诚信，血光消除恐惧消失，没有灾祸。'),(71,9,'爻辞',5,'九五：有孚挛如，富以其邻。','有诚信紧密相连，与邻居共同富裕。'),(72,9,'爻辞',6,'上九：既雨既处，尚德载，妇贞厉。月几望，君子征凶。','已经下雨已经停止，崇尚德行承载，妇人守正有危险。月亮将近满月，君子出征凶险。'),(73,10,'卦辞',NULL,'履：履虎尾，不咥人，亨。','履卦象征践行，踩到老虎尾巴，老虎不咬人，亨通。'),(74,10,'大象',NULL,'上天下泽，履；君子以辨上下，定民志。','上天下泽象征践行，君子应当分辨上下，安定民心。'),(75,10,'爻辞',1,'初九：素履，往无咎。','朴素地践行，前往没有灾祸。'),(76,10,'爻辞',2,'九二：履道坦坦，幽人贞吉。','践行大道平坦，隐士守正吉祥。'),(77,10,'爻辞',3,'六三：眇能视，跛能履，履虎尾，咥人，凶。武人为于大君。','独眼能看，跛脚能走，踩到老虎尾巴，老虎咬人，凶险。武人为大君效力。'),(78,10,'爻辞',4,'九四：履虎尾，愬愬终吉。','踩到老虎尾巴，小心翼翼最终吉祥。'),(79,10,'爻辞',5,'九五：夬履，贞厉。','果断践行，守正有危险。'),(80,10,'爻辞',6,'上九：视履考祥，其旋元吉。','审视践行考察吉凶，周旋得当大吉大利。'),(81,11,'卦辞',NULL,'泰：小往大来，吉亨。','泰卦象征通泰，小的往外大的来，吉祥亨通。'),(82,11,'大象',NULL,'天地交，泰；后以财成天地之道，辅相天地之宜，以左右民。','天地交合象征通泰，君主因此裁成天地之道，辅助天地之宜，以左右民众。'),(83,11,'爻辞',1,'初九：拔茅茹，以其汇，征吉。','拔茅草连根带出，因为它们连在一起，出征吉祥。'),(84,11,'爻辞',2,'九二：包荒，用冯河，不遐遗，朋亡，得尚于中行。','包容荒芜，徒步渡河，不遗弃远方，朋党消亡，得到中行的尊崇。'),(85,11,'爻辞',3,'九三：无平不陂，无往不复。艰贞无咎。勿恤其孚，于食有福。','没有平地不变成斜坡，没有去而不返。艰难守正没有灾祸。不要忧虑诚信，在饮食上有福。'),(86,11,'爻辞',4,'六四：翩翩不富，以其邻，不戒以孚。','翩翩然不富有，与邻居一起，不用告诫而有诚信。'),(87,11,'爻辞',5,'六五：帝乙归妹，以祉元吉。','帝乙嫁女，因此得福大吉大利。'),(88,11,'爻辞',6,'上六：城复于隍，勿用师。自邑告命，贞吝。','城墙倒塌入护城河，不要用兵。从邑中发布命令，守正有悔。'),(89,12,'卦辞',NULL,'否：否之匪人，不利君子贞，大往小来。','否卦象征闭塞，闭塞不是人道，不利于君子守正，大的往外小的来。'),(90,12,'大象',NULL,'天地不交，否；君子以俭德辟难，不可荣以禄。','天地不交象征闭塞，君子应当节俭德行避免灾难，不可以荣华富贵。'),(91,12,'爻辞',1,'初六：拔茅茹，以其汇，贞吉亨。','拔茅草连根带出，因为它们连在一起，守正吉祥亨通。'),(92,12,'爻辞',2,'六二：包承，小人吉，大人否亨。','包容承受，小人吉祥，大人闭塞而亨通。'),(93,12,'爻辞',3,'六三：包羞。','包容羞耻。'),(94,12,'爻辞',4,'九四：有命无咎，畴离祉。','有天命没有灾祸，同类都得到福祉。'),(95,12,'爻辞',5,'九五：休否，大人吉。其亡其亡，系于苞桑。','停止闭塞，大人吉祥。将要灭亡将要灭亡，系于丛生的桑树。'),(96,12,'爻辞',6,'上九：倾否，先否后喜。','倾覆闭塞，先闭塞后喜悦。'),(97,13,'卦辞',NULL,'同人：同人于野，亨。利涉大川，利君子贞。','同人卦象征与人和同，在野外与人和同，亨通。利于渡过大河，利于君子守正。'),(98,13,'大象',NULL,'天与火，同人；君子以类族辨物。','天与火象征与人和同，君子应当分类族群辨别事物。'),(99,13,'爻辞',1,'初九：同人于门，无咎。','在门口与人和同，没有灾祸。'),(100,13,'爻辞',2,'六二：同人于宗，吝。','在宗族中与人和同，有悔。'),(101,13,'爻辞',3,'九三：伏戎于莽，升其高陵，三岁不兴。','在草丛中埋伏军队，登上高陵，三年不能兴起。'),(102,13,'爻辞',4,'九四：乘其墉，弗克攻，吉。','登上城墙，不能攻克，吉祥。'),(103,13,'爻辞',5,'九五：同人，先号咷而后笑，大师克相遇。','与人和同，先号哭后欢笑，大军克敌后相遇。'),(104,13,'爻辞',6,'上九：同人于郊，无悔。','在郊外与人和同，没有悔恨。'),(105,14,'卦辞',NULL,'大有：元亨。','大有卦象征大有收获，元始亨通。'),(106,14,'大象',NULL,'火在天上，大有；君子以遏恶扬善，顺天休命。','火在天上象征大有，君子应当遏制邪恶弘扬善良，顺应天命。'),(107,14,'爻辞',1,'初九：无交害，匪咎，艰则无咎。','没有交往的害处，不是灾祸，艰难则没有灾祸。'),(108,14,'爻辞',2,'九二：大车以载，有攸往，无咎。','大车装载，有所往，没有灾祸。'),(109,14,'爻辞',3,'九三：公用亨于天子，小人弗克。','公侯用来朝见天子，小人不能做到。'),(110,14,'爻辞',4,'九四：匪其彭，无咎。','不是它的盛大，没有灾祸。'),(111,14,'爻辞',5,'六五：厥孚交如，威如，吉。','他的诚信交往，威严，吉祥。'),(112,14,'爻辞',6,'上九：自天祐之，吉无不利。','上天保佑他，吉祥无所不利。'),(113,15,'卦辞',NULL,'谦：亨，君子有终。','谦卦象征谦逊，亨通，君子有好的结局。'),(114,15,'大象',NULL,'地中有山，谦；君子以裒多益寡，称物平施。','地中有山象征谦逊，君子应当减少多余增加不足，称量事物公平施予。'),(115,15,'爻辞',1,'初六：谦谦君子，用涉大川，吉。','谦逊再谦逊的君子，用来渡过大河，吉祥。'),(116,15,'爻辞',2,'六二：鸣谦，贞吉。','名声谦逊，守正吉祥。'),(117,15,'爻辞',3,'九三：劳谦，君子有终，吉。','勤劳谦逊，君子有好的结局，吉祥。'),(118,15,'爻辞',4,'六四：无不利，撝谦。','无所不利，发挥谦逊。'),(119,15,'爻辞',5,'六五：不富以其邻，利用侵伐，无不利。','不富有而与邻居一起，利于征伐，无所不利。'),(120,15,'爻辞',6,'上六：鸣谦，利用行师，征邑国。','名声谦逊，利于出兵，征伐邑国。'),(121,16,'卦辞',NULL,'豫：利建侯行师。','豫卦象征欢乐，利于建立诸侯出兵征伐。'),(122,16,'大象',NULL,'雷出地奋，豫；先王以作乐崇德，殷荐之上帝，以配祖考。','雷从地中奋起象征欢乐，先王因此制作音乐崇尚德行，隆重地献给上帝，以配享祖先。'),(123,16,'爻辞',1,'初六：鸣豫，凶。','鸣叫欢乐，凶险。'),(124,16,'爻辞',2,'六二：介于石，不终日，贞吉。','坚如磐石，不到一天，守正吉祥。'),(125,16,'爻辞',3,'六三：盱豫，悔。迟有悔。','仰视欢乐，有悔。迟疑有悔。'),(126,16,'爻辞',4,'九四：由豫，大有得。勿疑，朋盍簪。','由于欢乐，大有收获。不要怀疑，朋友聚集如簪。'),(127,16,'爻辞',5,'六五：贞疾，恒不死。','守正有疾病，长久不死。'),(128,16,'爻辞',6,'上六：冥豫，成有渝，无咎。','昏暗的欢乐，成功有变化，没有灾祸。'),(129,17,'卦辞',NULL,'随：元亨利贞，无咎。','随卦象征随从，元始亨通利于守正，没有灾祸。'),(130,17,'大象',NULL,'泽中有雷，随；君子以向晦入宴息。','泽中有雷象征随从，君子应当日落时休息。'),(131,17,'爻辞',1,'初九：官有渝，贞吉。出门交有功。','官职有变化，守正吉祥。出门交往有功。'),(132,17,'爻辞',2,'六二：系小子，失丈夫。','系住小孩，失去丈夫。'),(133,17,'爻辞',3,'六三：系丈夫，失小子。随有求得，利居贞。','系住丈夫，失去小孩。随从有所求得，利于安居守正。'),(134,17,'爻辞',4,'九四：随有获，贞凶。有孚在道，以明，何咎。','随从有所获，守正凶险。有诚信在道，以明察，有什么灾祸。'),(135,17,'爻辞',5,'九五：孚于嘉，吉。','诚信于美善，吉祥。'),(136,17,'爻辞',6,'上六：拘系之，乃从维之。王用亨于西山。','拘禁系住他，于是随从维系他。君王用来祭享于西山。'),(137,18,'卦辞',NULL,'蛊：元亨，利涉大川。先甲三日，后甲三日。','蛊卦象征整治弊病，元始亨通，利于渡过大河。甲日前三天，甲日后三天。'),(138,18,'大象',NULL,'山下有风，蛊；君子以振民育德。','山下有风象征蛊惑，君子应当振兴民众培育德行。'),(139,18,'爻辞',1,'初六：干父之蛊，有子，考无咎，厉终吉。','整治父亲的弊病，有儿子，父亲没有灾祸，危险最终吉祥。'),(140,18,'爻辞',2,'九二：干母之蛊，不可贞。','整治母亲的弊病，不可守正。'),(141,18,'爻辞',3,'九三：干父之蛊，小有悔，无大咎。','整治父亲的弊病，稍有悔恨，没有大灾祸。'),(142,18,'爻辞',4,'六四：裕父之蛊，往见吝。','宽裕父亲的弊病，前往有悔。'),(143,18,'爻辞',5,'六五：干父之蛊，用誉。','整治父亲的弊病，用荣誉。'),(144,18,'爻辞',6,'上九：不事王侯，高尚其事。','不事奉王侯，高尚其事业。'),(145,19,'卦辞',NULL,'临：元亨利贞。至于八月有凶。','临卦象征临近，元始亨通利于守正。到了八月有凶险。'),(146,19,'大象',NULL,'泽上有地，临；君子以教思无穷，容保民无疆。','泽上有地象征临近，君子应当教化思虑无穷，容纳保护民众无边。'),(147,19,'爻辞',1,'初九：咸临，贞吉。','感应临近，守正吉祥。'),(148,19,'爻辞',2,'九二：咸临，吉无不利。','感应临近，吉祥无所不利。'),(149,19,'爻辞',3,'六三：甘临，无攸利。既忧之，无咎。','甘美地临近，没有什么利益。既然忧虑它，没有灾祸。'),(150,19,'爻辞',4,'六四：至临，无咎。','到达临近，没有灾祸。'),(151,19,'爻辞',5,'六五：知临，大君之宜，吉。','智慧地临近，大君的适宜，吉祥。'),(152,19,'爻辞',6,'上六：敦临，吉无咎。','敦厚地临近，吉祥没有灾祸。'),(153,20,'卦辞',NULL,'观：盥而不荐，有孚颙若。','观卦象征观看，洗手而不献祭，有诚信庄严的样子。'),(154,20,'大象',NULL,'风行地上，观；先王以省方观民设教。','风行于地上象征观看，先王因此巡视四方观察民情设立教化。'),(155,20,'爻辞',1,'初六：童观，小人无咎，君子吝。','童稚地观看，小人没有灾祸，君子有悔。'),(156,20,'爻辞',2,'六二：窥观，利女贞。','窥视观看，利于女子守正。'),(157,20,'爻辞',3,'六三：观我生，进退。','观察我的生活，进退。'),(158,20,'爻辞',4,'六四：观国之光，利用宾于王。','观察国家的光荣，利于作为宾客于君王。'),(159,20,'爻辞',5,'九五：观我生，君子无咎。','观察我的生活，君子没有灾祸。'),(160,20,'爻辞',6,'上九：观其生，君子无咎。','观察他的生活，君子没有灾祸。'),(161,21,'卦辞',NULL,'噬嗑：亨。利用狱。','噬嗑卦象征咬合，亨通。利于用刑狱。'),(162,21,'大象',NULL,'雷电噬嗑；先王以明罚敕法。','雷电象征噬嗑，先王因此明确刑罚整饬法律。'),(163,21,'爻辞',1,'初九：屦校灭趾，无咎。','脚戴刑具伤了脚趾，没有灾祸。'),(164,21,'爻辞',2,'六二：噬肤灭鼻，无咎。','咬皮肤伤了鼻子，没有灾祸。'),(165,21,'爻辞',3,'六三：噬腊肉，遇毒；小吝，无咎。','咬腊肉，遇到毒；稍有悔，没有灾祸。'),(166,21,'爻辞',4,'九四：噬干胏，得金矢，利艰贞，吉。','咬干肉带骨，得到金箭，利于艰难守正，吉祥。'),(167,21,'爻辞',5,'六五：噬干肉，得黄金，贞厉，无咎。','咬干肉，得到黄金，守正有危险，没有灾祸。'),(168,21,'爻辞',6,'上九：何校灭耳，凶。','颈戴刑具伤了耳朵，凶险。'),(169,22,'卦辞',NULL,'贲：亨。小利有攸往。','贲卦象征文饰，亨通。小利于有所往。'),(170,22,'大象',NULL,'山下有火，贲；君子以明庶政，无敢折狱。','山下有火象征文饰，君子应当明察政事，不敢轻易断狱。'),(171,22,'爻辞',1,'初九：贲其趾，舍车而徒。','文饰脚趾，舍弃车而步行。'),(172,22,'爻辞',2,'六二：贲其须。','文饰胡须。'),(173,22,'爻辞',3,'九三：贲如濡如，永贞吉。','文饰润泽，永久守正吉祥。'),(174,22,'爻辞',4,'六四：贲如皤如，白马翰如。匪寇婚媾。','文饰洁白，白马飞驰。不是强盗而是求婚者。'),(175,22,'爻辞',5,'六五：贲于丘园，束帛戋戋，吝，终吉。','文饰于丘园，束帛微薄，有悔，最终吉祥。'),(176,22,'爻辞',6,'上九：白贲，无咎。','白色文饰，没有灾祸。'),(177,23,'卦辞',NULL,'剥：不利有攸往。','剥卦象征剥落，不利于有所往。'),(178,23,'大象',NULL,'山附于地，剥；上以厚下安宅。','山附于地象征剥落，君上应当厚待下民安定居所。'),(179,23,'爻辞',1,'初六：剥床以足，蔑贞凶。','剥落床的脚，灭正凶险。'),(180,23,'爻辞',2,'六二：剥床以辨，蔑贞凶。','剥落床的边框，灭正凶险。'),(181,23,'爻辞',3,'六三：剥之，无咎。','剥落它，没有灾祸。'),(182,23,'爻辞',4,'六四：剥床以肤，凶。','剥落床到皮肤，凶险。'),(183,23,'爻辞',5,'六五：贯鱼，以宫人宠，无不利。','贯穿鱼，以宫人受宠，无所不利。'),(184,23,'爻辞',6,'上九：硕果不食，君子得舆，小人剥庐。','大果实不吃，君子得到车，小人剥落房屋。'),(185,24,'卦辞',NULL,'复：亨。出入无疾，朋来无咎。反复其道，七日来复，利有攸往。','复卦象征回复，亨通。出入没有疾病，朋友来没有灾祸。反复其道，七日来复，利于有所往。'),(186,24,'大象',NULL,'雷在地中，复；先王以至日闭关，商旅不行，后不省方。','雷在地中象征回复，先王因此在冬至日关闭关口，商旅不行，君主不巡视四方。'),(187,24,'爻辞',1,'初九：不远复，无祗悔，元吉。','不远就回复，没有大悔，大吉大利。'),(188,24,'爻辞',2,'六二：休复，吉。','美好地回复，吉祥。'),(189,24,'爻辞',3,'六三：频复，厉无咎。','频繁回复，危险没有灾祸。'),(190,24,'爻辞',4,'六四：中行独复。','中道独自回复。'),(191,24,'爻辞',5,'六五：敦复，无悔。','敦厚地回复，没有悔恨。'),(192,24,'爻辞',6,'上六：迷复，凶，有灾眚。用行师，终有大败，以其国君，凶；至于十年，不克征。','迷失回复，凶险，有灾祸。用来出兵，最终大败，连累国君，凶险；到了十年，不能征伐。'),(193,25,'卦辞',NULL,'无妄：元亨利贞。其匪正有眚，不利有攸往。','无妄卦象征无妄，元始亨通利于守正。不正则有灾祸，不利于有所往。'),(194,25,'大象',NULL,'天下雷行，物与无妄；先王以茂对时育万物。','天下雷行，万物与无妄；先王因此茂盛地对应时节养育万物。'),(195,25,'爻辞',1,'初九：无妄，往吉。','无妄，前往吉祥。'),(196,25,'爻辞',2,'六二：不耕获，不菑畲，则利有攸往。','不耕种而收获，不开垦而种植，则利于有所往。'),(197,25,'爻辞',3,'六三：无妄之灾，或系之牛，行人之得，邑人之灾。','无妄的灾祸，或许系住的牛，行人得到，邑人遭灾。'),(198,25,'爻辞',4,'九四：可贞，无咎。','可以守正，没有灾祸。'),(199,25,'爻辞',5,'九五：无妄之疾，勿药有喜。','无妄的疾病，不用药而有喜。'),(200,25,'爻辞',6,'上九：无妄，行有眚，无攸利。','无妄，行动有灾祸，没有什么利益。'),(201,26,'卦辞',NULL,'大畜：利贞，不家食吉，利涉大川。','大畜卦象征大有积蓄，利于守正，不在家吃饭吉祥，利于渡过大河。'),(202,26,'大象',NULL,'天在山中，大畜；君子以多识前言往行，以畜其德。','天在山中象征大有积蓄，君子应当多识前人言行，以积蓄德行。'),(203,26,'爻辞',1,'初九：有厉，利已。','有危险，利于停止。'),(204,26,'爻辞',2,'九二：舆说輹。','车脱落车轴。'),(205,26,'爻辞',3,'九三：良马逐，利艰贞。曰闲舆卫，利有攸往。','良马追逐，利于艰难守正。说练习车战防卫，利于有所往。'),(206,26,'爻辞',4,'六四：童牛之牿，元吉。','小牛的牛角套上横木，大吉大利。'),(207,26,'爻辞',5,'六五：豮豕之牙，吉。','阉猪的牙，吉祥。'),(208,26,'爻辞',6,'上九：何天之衢，亨。','何等天的大道，亨通。'),(209,27,'卦辞',NULL,'颐：贞吉。观颐，自求口实。','颐卦象征颐养，守正吉祥。观察颐养，自己求取口中食物。'),(210,27,'大象',NULL,'山下有雷，颐；君子以慎言语，节饮食。','山下有雷象征颐养，君子应当谨慎言语，节制饮食。'),(211,27,'爻辞',1,'初九：舍尔灵龟，观我朵颐，凶。','舍弃你的灵龟，观看我鼓动腮帮，凶险。'),(212,27,'爻辞',2,'六二：颠颐，拂经，于丘颐，征凶。','颠倒颐养，违背常理，在丘陵颐养，出征凶险。'),(213,27,'爻辞',3,'六三：拂颐，贞凶，十年勿用，无攸利。','违背颐养，守正凶险，十年不用，没有什么利益。'),(214,27,'爻辞',4,'六四：颠颐，吉。虎视眈眈，其欲逐逐，无咎。','颠倒颐养，吉祥。虎视眈眈，其欲望追逐，没有灾祸。'),(215,27,'爻辞',5,'六五：拂经，居贞吉，不可涉大川。','违背常理，安居守正吉祥，不可渡过大河。'),(216,27,'爻辞',6,'上九：由颐，厉吉，利涉大川。','由于颐养，危险吉祥，利于渡过大河。'),(217,28,'卦辞',NULL,'大过：栋桡，利有攸往，亨。','大过卦象征大过，栋梁弯曲，利于有所往，亨通。'),(218,28,'大象',NULL,'泽灭木，大过；君子以独立不惧，遁世无闷。','泽水淹没树木象征大过，君子应当独立不惧，遁世无闷。'),(219,28,'爻辞',1,'初六：藉用白茅，无咎。','用白茅垫底，没有灾祸。'),(220,28,'爻辞',2,'九二：枯杨生稊，老夫得其女妻，无不利。','枯杨生出嫩芽，老夫得到年轻妻子，无所不利。'),(221,28,'爻辞',3,'九三：栋桡，凶。','栋梁弯曲，凶险。'),(222,28,'爻辞',4,'九四：栋隆，吉；有它吝。','栋梁高隆，吉祥；有其他则有悔。'),(223,28,'爻辞',5,'九五：枯杨生华，老妇得其士夫，无咎无誉。','枯杨开花，老妇得到年轻丈夫，没有灾祸没有荣誉。'),(224,28,'爻辞',6,'上六：过涉灭顶，凶，无咎。','过度涉水淹没头顶，凶险，没有灾祸。'),(225,29,'卦辞',NULL,'坎：习坎，有孚，维心亨，行有尚。','坎卦象征险陷，重重险陷，有诚信，维系心志亨通，行动有嘉尚。'),(226,29,'大象',NULL,'水洊至，习坎；君子以常德行，习教事。','水重重而至象征险陷，君子应当常行德行，习练教事。'),(227,29,'爻辞',1,'初六：习坎，入于坎窞，凶。','重重险陷，进入坎穴，凶险。'),(228,29,'爻辞',2,'九二：坎有险，求小得。','坎有险阻，求小有所得。'),(229,29,'爻辞',3,'六三：来之坎坎，险且枕，入于坎窞，勿用。','来去都是坎险，险阻且停留，进入坎穴，不要有所作为。'),(230,29,'爻辞',4,'六四：樽酒簋贰，用缶，纳约自牖，终无咎。','一樽酒两簋食，用瓦器，从窗户送入简约，最终没有灾祸。'),(231,29,'爻辞',5,'九五：坎不盈，祗既平，无咎。','坎不满溢，只是已经平，没有灾祸。'),(232,29,'爻辞',6,'上六：系用徽纆，寘于丛棘，三岁不得，凶。','用绳索捆绑，置于丛棘中，三年不能脱身，凶险。'),(233,30,'卦辞',NULL,'离：利贞，亨。畜牝牛，吉。','离卦象征附丽，利于守正，亨通。畜养母牛，吉祥。'),(234,30,'大象',NULL,'明两作，离；大人以继明照于四方。','光明两次升起象征附丽，大人因此继续光明照耀四方。'),(235,30,'爻辞',1,'初九：履错然，敬之无咎。','行走错杂，恭敬则没有灾祸。'),(236,30,'爻辞',2,'六二：黄离，元吉。','黄色附丽，大吉大利。'),(237,30,'爻辞',3,'九三：日昃之离，不鼓缶而歌，则大耋之嗟，凶。','日落时的附丽，不敲瓦器而歌唱，则老年的叹息，凶险。'),(238,30,'爻辞',4,'九四：突如其来如，焚如，死如，弃如。','突然而来，焚烧，死亡，抛弃。'),(239,30,'爻辞',5,'六五：出涕沱若，戚嗟若，吉。','流泪滂沱，忧戚叹息，吉祥。'),(240,30,'爻辞',6,'上九：王用出征，有嘉折首，获匪其丑，无咎。','君王用来出征，有嘉奖斩首，俘获不是其同类，没有灾祸。'),(241,31,'卦辞',NULL,'咸：亨，利贞，取女吉。','咸卦象征感应，亨通，利于守正，娶女吉祥。'),(242,31,'大象',NULL,'山上有泽，咸；君子以虚受人。','山上有泽象征感应，君子应当虚心接受他人。'),(243,31,'爻辞',1,'初六：咸其拇。','感应于脚拇指。'),(244,31,'爻辞',2,'六二：咸其腓，凶，居吉。','感应于小腿，凶险，安居吉祥。'),(245,31,'爻辞',3,'九三：咸其股，执其随，往吝。','感应于大腿，执着于随从，前往有悔。'),(246,31,'爻辞',4,'九四：贞吉悔亡，憧憧往来，朋从尔思。','守正吉祥悔恨消亡，心神不定往来，朋友随从你的思想。'),(247,31,'爻辞',5,'九五：咸其脢，无悔。','感应于背脊，没有悔恨。'),(248,31,'爻辞',6,'上六：咸其辅颊舌。','感应于牙床、脸颊、舌头。'),(249,32,'卦辞',NULL,'恒：亨，无咎，利贞，利有攸往。','恒卦象征恒久，亨通，没有灾祸，利于守正，利于有所往。'),(250,32,'大象',NULL,'雷风恒；君子以立不易方。','雷风象征恒久，君子应当立身不改变方向。'),(251,32,'爻辞',1,'初六：浚恒，贞凶，无攸利。','深求恒久，守正凶险，没有什么利益。'),(252,32,'爻辞',2,'九二：悔亡。','悔恨消亡。'),(253,32,'爻辞',3,'九三：不恒其德，或承之羞，贞吝。','不恒久其德行，或许承受羞辱，守正有悔。'),(254,32,'爻辞',4,'九四：田无禽。','田猎没有禽兽。'),(255,32,'爻辞',5,'六五：恒其德，贞，妇人吉，夫子凶。','恒久其德行，守正，妇人吉祥，丈夫凶险。'),(256,32,'爻辞',6,'上六：振恒，凶。','振动恒久，凶险。'),(257,33,'卦辞',NULL,'遁：亨，小利贞。','遁卦象征退避，亨通，小利于守正。'),(258,33,'大象',NULL,'天下有山，遁；君子以远小人，不恶而严。','天下有山象征退避，君子应当远离小人，不厌恶而严肃。'),(259,33,'爻辞',1,'初六：遁尾，厉，勿用有攸往。','退避在尾部，危险，不要有所往。'),(260,33,'爻辞',2,'六二：执之用黄牛之革，莫之胜说。','用黄牛皮绑住他，没有人能解脱。'),(261,33,'爻辞',3,'九三：系遁，有疾厉，畜臣妾吉。','系住退避，有疾病危险，畜养臣妾吉祥。'),(262,33,'爻辞',4,'九四：好遁，君子吉，小人否。','美好地退避，君子吉祥，小人不吉。'),(263,33,'爻辞',5,'九五：嘉遁，贞吉。','美好地退避，守正吉祥。'),(264,33,'爻辞',6,'上九：肥遁，无不利。','丰裕地退避，无所不利。'),(265,34,'卦辞',NULL,'大壮：利贞。','大壮卦象征大壮，利于守正。'),(266,34,'大象',NULL,'雷在天上，大壮；君子以非礼弗履。','雷在天上象征大壮，君子应当不合礼的不做。'),(267,34,'爻辞',1,'初九：壮于趾，征凶，有孚。','壮于脚趾，出征凶险，有诚信。'),(268,34,'爻辞',2,'九二：贞吉。','守正吉祥。'),(269,34,'爻辞',3,'九三：小人用壮，君子用罔，贞厉。羝羊触藩，羸其角。','小人用壮，君子用网，守正危险。公羊触撞篱笆，困住了角。'),(270,34,'爻辞',4,'九四：贞吉悔亡，藩决不羸，壮于大舆之輹。','守正吉祥悔恨消亡，篱笆决裂不困，壮于大车的车轴。'),(271,34,'爻辞',5,'六五：丧羊于易，无悔。','在易地丧失羊，没有悔恨。'),(272,34,'爻辞',6,'上六：羝羊触藩，不能退，不能遂，无攸利，艰则吉。','公羊触撞篱笆，不能退，不能进，没有什么利益，艰难则吉祥。'),(273,35,'卦辞',NULL,'晋：康侯用锡马蕃庶，昼日三接。','晋卦象征晋升，康侯用赐予的马繁殖众多，一天三次接见。'),(274,35,'大象',NULL,'明出地上，晋；君子以自昭明德。','光明出于地上象征晋升，君子应当自己彰显明德。'),(275,35,'爻辞',1,'初六：晋如，摧如，贞吉。罔孚，裕无咎。','晋升，受挫，守正吉祥。没有诚信，宽裕没有灾祸。'),(276,35,'爻辞',2,'六二：晋如，愁如，贞吉。受兹介福，于其王母。','晋升，忧愁，守正吉祥。受此大福，于其祖母。'),(277,35,'爻辞',3,'六三：众允，悔亡。','众人信任，悔恨消亡。'),(278,35,'爻辞',4,'九四：晋如鼫鼠，贞厉。','晋升如鼫鼠，守正危险。'),(279,35,'爻辞',5,'六五：悔亡，失得勿恤，往吉无不利。','悔恨消亡，失得不要忧虑，前往吉祥无所不利。'),(280,35,'爻辞',6,'上九：晋其角，维用伐邑，厉吉无咎，贞吝。','晋升其角，只用来征伐邑，危险吉祥没有灾祸，守正有悔。'),(281,36,'卦辞',NULL,'明夷：利艰贞。','明夷卦象征光明受损，利于艰难守正。'),(282,36,'大象',NULL,'明入地中，明夷；君子以莅众，用晦而明。','光明入于地中象征明夷，君子应当治理众人，用晦暗而明察。'),(283,36,'爻辞',1,'初九：明夷于飞，垂其翼。君子于行，三日不食，有攸往，主人有言。','光明受损于飞行，垂下翅膀。君子在行走，三天不吃，有所往，主人有话说。'),(284,36,'爻辞',2,'六二：明夷，夷于左股，用拯马壮，吉。','光明受损，伤于左腿，用壮马拯救，吉祥。'),(285,36,'爻辞',3,'九三：明夷于南狩，得其大首，不可疾贞。','光明受损于南方狩猎，得到大首领，不可急于守正。'),(286,36,'爻辞',4,'六四：入于左腹，获明夷之心，出于门庭。','进入左腹，获得明夷的心意，出于门庭。'),(287,36,'爻辞',5,'六五：箕子之明夷，利贞。','箕子的光明受损，利于守正。'),(288,36,'爻辞',6,'上六：不明晦，初登于天，后入于地。','不明而晦暗，开始登于天，后来入于地。'),(289,37,'卦辞',NULL,'家人：利女贞。','家人卦象征家人，利于女子守正。'),(290,37,'大象',NULL,'风自火出，家人；君子以言有物而行有恒。','风从火出象征家人，君子应当言语有内容而行为有恒心。'),(291,37,'爻辞',1,'初九：闲有家，悔亡。','防闲有家，悔恨消亡。'),(292,37,'爻辞',2,'六二：无攸遂，在中馈，贞吉。','没有什么成就，在中馈食，守正吉祥。'),(293,37,'爻辞',3,'九三：家人嗃嗃，悔厉吉；妇子嘻嘻，终吝。','家人严厉，悔恨危险吉祥；妇女孩子嬉笑，最终有悔。'),(294,37,'爻辞',4,'六四：富家，大吉。','富裕家庭，大吉大利。'),(295,37,'爻辞',5,'九五：王假有家，勿恤吉。','君王到达有家，不要忧虑吉祥。'),(296,37,'爻辞',6,'上九：有孚威如，终吉。','有诚信威严，最终吉祥。'),(297,38,'卦辞',NULL,'睽：小事吉。','睽卦象征乖离，小事吉祥。'),(298,38,'大象',NULL,'上火下泽，睽；君子以同而异。','上火下泽象征乖离，君子应当求同存异。'),(299,38,'爻辞',1,'初九：悔亡，丧马勿逐，自复；见恶人无咎。','悔恨消亡，丧失马不要追逐，自己回来；见恶人没有灾祸。'),(300,38,'爻辞',2,'九二：遇主于巷，无咎。','在巷中遇到主人，没有灾祸。'),(301,38,'爻辞',3,'六三：见舆曳，其牛掣，其人天且劓，无初有终。','见车被拖，其牛被牵，其人受刑，没有开始有结局。'),(302,38,'爻辞',4,'九四：睽孤，遇元夫，交孚，厉无咎。','乖离孤独，遇到善人，交往诚信，危险没有灾祸。'),(303,38,'爻辞',5,'六五：悔亡，厥宗噬肤，往何咎。','悔恨消亡，其宗族咬皮肤，前往有什么灾祸。'),(304,38,'爻辞',6,'上九：睽孤，见豕负涂，载鬼一车，先张之弧，后说之弧，匪寇婚媾，往遇雨则吉。','乖离孤独，见猪背负泥土，载鬼一车，先张弓，后放下弓，不是强盗而是求婚者，前往遇雨则吉祥。'),(305,39,'卦辞',NULL,'蹇：利西南，不利东北。利见大人，贞吉。','蹇卦象征艰难，利于西南，不利于东北。利于拜见大人，守正吉祥。'),(306,39,'大象',NULL,'山上有水，蹇；君子以反身修德。','山上有水象征艰难，君子应当反省自身修养德行。'),(307,39,'爻辞',1,'初六：往蹇，来誉。','前往艰难，回来有荣誉。'),(308,39,'爻辞',2,'六二：王臣蹇蹇，匪躬之故。','王臣艰难重重，不是自身的缘故。'),(309,39,'爻辞',3,'九三：往蹇来反。','前往艰难回来返回。'),(310,39,'爻辞',4,'六四：往蹇来连。','前往艰难回来连接。'),(311,39,'爻辞',5,'九五：大蹇朋来。','大艰难朋友来。'),(312,39,'爻辞',6,'上六：往蹇来硕，吉；利见大人。','前往艰难回来丰硕，吉祥；利于拜见大人。'),(313,40,'卦辞',NULL,'解：利西南，无所往，其来复吉。有攸往，夙吉。','解卦象征解除，利于西南，无所往，回来吉祥。有所往，早去吉祥。'),(314,40,'大象',NULL,'雷雨作，解；君子以赦过宥罪。','雷雨兴起象征解除，君子应当赦免过错宽宥罪行。'),(315,40,'爻辞',1,'初六：无咎。','没有灾祸。'),(316,40,'爻辞',2,'九二：田获三狐，得黄矢，贞吉。','田猎获得三只狐狸，得到黄色箭矢，守正吉祥。'),(317,40,'爻辞',3,'六三：负且乘，致寇至，贞吝。','背负且乘车，招致盗寇到来，守正有悔。'),(318,40,'爻辞',4,'九四：解而拇，朋至斯孚。','解除你的脚拇指，朋友到来才有诚信。'),(319,40,'爻辞',5,'六五：君子维有解，吉；有孚于小人。','君子只有解除，吉祥；有诚信于小人。'),(320,40,'爻辞',6,'上六：公用射隼于高墉之上，获之，无不利。','公侯用来射隼于高墙之上，获得它，无所不利。'),(321,41,'卦辞',NULL,'损：有孚，元吉，无咎，可贞，利有攸往。曷之用？二簋可用享。','损卦象征减损，有诚信，大吉大利，没有灾祸，可以守正，利于有所往。用什么？两簋可以用来祭享。'),(322,41,'大象',NULL,'山下有泽，损；君子以惩忿窒欲。','山下有泽象征减损，君子应当惩戒愤怒抑制欲望。'),(323,41,'爻辞',1,'初九：已事遄往，无咎，酌损之。','事情完成迅速前往，没有灾祸，酌量减损。'),(324,41,'爻辞',2,'九二：利贞，征凶，弗损益之。','利于守正，出征凶险，不减损而增益。'),(325,41,'爻辞',3,'六三：三人行，则损一人；一人行，则得其友。','三人同行，则减损一人；一人独行，则得到朋友。'),(326,41,'爻辞',4,'六四：损其疾，使遄有喜，无咎。','减损其疾病，使迅速有喜，没有灾祸。'),(327,41,'爻辞',5,'六五：或益之十朋之龟，弗克违，元吉。','或许增益十朋的龟，不能违背，大吉大利。'),(328,41,'爻辞',6,'上九：弗损益之，无咎，贞吉，利有攸往，得臣无家。','不减损而增益，没有灾祸，守正吉祥，利于有所往，得到臣子没有私家。'),(329,42,'卦辞',NULL,'益：利有攸往，利涉大川。','益卦象征增益，利于有所往，利于渡过大河。'),(330,42,'大象',NULL,'风雷益；君子以见善则迁，有过则改。','风雷象征增益，君子应当见到善就学习，有过错就改正。'),(331,42,'爻辞',1,'初九：利用为大作，元吉，无咎。','利于做大事，大吉大利，没有灾祸。'),(332,42,'爻辞',2,'六二：或益之十朋之龟，弗克违，永贞吉。王用享于帝，吉。','或许增益十朋的龟，不能违背，永久守正吉祥。君王用来祭享上帝，吉祥。'),(333,42,'爻辞',3,'六三：益之用凶事，无咎。有孚中行，告公用圭。','增益用于凶事，没有灾祸。有诚信中行，告诉公侯用圭。'),(334,42,'爻辞',4,'六四：中行，告公从。利用为依迁国。','中行，告诉公侯随从。利于作为依靠迁国。'),(335,42,'爻辞',5,'九五：有孚惠心，勿问元吉。有孚惠我德。','有诚信惠心，不用问大吉大利。有诚信惠我德行。'),(336,42,'爻辞',6,'上九：莫益之，或击之，立心勿恒，凶。','没有增益，或许攻击，立心不恒久，凶险。'),(337,43,'卦辞',NULL,'夬：扬于王庭，孚号，有厉。告自邑，不利即戎，利有攸往。','夬卦象征决断，在王庭宣扬，诚信号召，有危险。从邑中告知，不利于用兵，利于有所往。'),(338,43,'大象',NULL,'泽上于天，夬；君子以施禄及下，居德则忌。','泽上于天象征决断，君子应当施予俸禄及于下民，居于德行则忌讳。'),(339,43,'爻辞',1,'初九：壮于前趾，往不胜为咎。','壮于前脚趾，前往不胜为灾祸。'),(340,43,'爻辞',2,'九二：惕号，莫夜有戎，勿恤。','警惕号召，暮夜有兵戎，不要忧虑。'),(341,43,'爻辞',3,'九三：壮于頄，有凶。君子夬夬，独行遇雨，若濡有愠，无咎。','壮于颧骨，有凶险。君子决断决断，独行遇雨，若沾湿有愠怒，没有灾祸。'),(342,43,'爻辞',4,'九四：臀无肤，其行次且。牵羊悔亡，闻言不信。','臀部没有皮肤，其行走艰难。牵羊悔恨消亡，听言不信。'),(343,43,'爻辞',5,'九五：苋陆夬夬，中行无咎。','苋陆决断决断，中行没有灾祸。'),(344,43,'爻辞',6,'上六：无号，终有凶。','没有号召，最终有凶险。'),(345,44,'卦辞',NULL,'姤：女壮，勿用取女。','姤卦象征相遇，女子强壮，不要娶这样的女子。'),(346,44,'大象',NULL,'天下有风，姤；后以施命诰四方。','天下有风象征相遇，君主因此发布命令告诫四方。'),(347,44,'爻辞',1,'初六：系于金柅，贞吉，有攸往，见凶，羸豕孚蹢躅。','系于金属车闸，守正吉祥，有所往，见凶险，瘦猪诚信踯躅。'),(348,44,'爻辞',2,'九二：包有鱼，无咎，不利宾。','包中有鱼，没有灾祸，不利于宾客。'),(349,44,'爻辞',3,'九三：臀无肤，其行次且，厉，无大咎。','臀部没有皮肤，其行走艰难，危险，没有大灾祸。'),(350,44,'爻辞',4,'九四：包无鱼，起凶。','包中没有鱼，起凶险。'),(351,44,'爻辞',5,'九五：以杞包瓜，含章，有陨自天。','用杞树包瓜，含蓄美德，有陨落自天。'),(352,44,'爻辞',6,'上九：姤其角，吝，无咎。','相遇于角，有悔，没有灾祸。'),(353,45,'卦辞',NULL,'萃：亨。王假有庙，利见大人，亨，利贞。用大牲吉，利有攸往。','萃卦象征聚集，亨通。君王到达宗庙，利于拜见大人，亨通，利于守正。用大牲畜祭祀吉祥，利于有所往。'),(354,45,'大象',NULL,'泽上于地，萃；君子以除戎器，戒不虞。','泽上于地象征聚集，君子应当整治兵器，戒备意外。'),(355,45,'爻辞',1,'初六：有孚不终，乃乱乃萃，若号一握为笑，勿恤，往无咎。','有诚信不终，于是乱于是聚，若号哭一握为笑，不要忧虑，前往没有灾祸。'),(356,45,'爻辞',2,'六二：引吉，无咎，孚乃利用禴。','引导吉祥，没有灾祸，诚信才利于禴祭。'),(357,45,'爻辞',3,'六三：萃如，嗟如，无攸利，往无咎，小吝。','聚集，叹息，没有什么利益，前往没有灾祸，稍有悔。'),(358,45,'爻辞',4,'九四：大吉，无咎。','大吉大利，没有灾祸。'),(359,45,'爻辞',5,'九五：萃有位，无咎。匪孚，元永贞，悔亡。','聚集有位，没有灾祸。没有诚信，元始永久守正，悔恨消亡。'),(360,45,'爻辞',6,'上六：赍咨涕洟，无咎。','叹息流泪流涕，没有灾祸。'),(361,46,'卦辞',NULL,'升：元亨，用见大人，勿恤，南征吉。','升卦象征上升，元始亨通，用来拜见大人，不要忧虑，南征吉祥。'),(362,46,'大象',NULL,'地中生木，升；君子以顺德，积小以高大。','地中生木象征上升，君子应当顺应德行，积累小的以成高大。'),(363,46,'爻辞',1,'初六：允升，大吉。','诚信上升，大吉大利。'),(364,46,'爻辞',2,'九二：孚乃利用禴，无咎。','诚信才利于禴祭，没有灾祸。'),(365,46,'爻辞',3,'九三：升虚邑。','上升于空虚的邑。'),(366,46,'爻辞',4,'六四：王用亨于岐山，吉，无咎。','君王用来祭享于岐山，吉祥，没有灾祸。'),(367,46,'爻辞',5,'六五：贞吉，升阶。','守正吉祥，上升台阶。'),(368,46,'爻辞',6,'上六：冥升，利于不息之贞。','昏暗上升，利于不息的守正。'),(369,47,'卦辞',NULL,'困：亨，贞，大人吉，无咎，有言不信。','困卦象征困顿，亨通，守正，大人吉祥，没有灾祸，有言语不被信任。'),(370,47,'大象',NULL,'泽无水，困；君子以致命遂志。','泽中无水象征困顿，君子应当舍命以遂志向。'),(371,47,'爻辞',1,'初六：臀困于株木，入于幽谷，三岁不觌。','臀部困于树桩，进入幽谷，三年不见。'),(372,47,'爻辞',2,'九二：困于酒食，朱绂方来，利用享祀，征凶，无咎。','困于酒食，朱色蔽膝正来，利于祭祀，出征凶险，没有灾祸。'),(373,47,'爻辞',3,'六三：困于石，据于蒺藜，入于其宫，不见其妻，凶。','困于石头，靠于蒺藜，进入其宫室，不见其妻子，凶险。'),(374,47,'爻辞',4,'九四：来徐徐，困于金车，吝，有终。','来得缓慢，困于金车，有悔，有结局。'),(375,47,'爻辞',5,'九五：劓刖，困于赤绂，乃徐有说，利用祭祀。','割鼻断足，困于赤色蔽膝，于是缓慢有喜悦，利于祭祀。'),(376,47,'爻辞',6,'上六：困于葛藟，于臲卼，曰动悔。有悔，征吉。','困于葛藤，于动摇，说动则悔。有悔恨，出征吉祥。'),(377,48,'卦辞',NULL,'井：改邑不改井，无丧无得，往来井井。汔至，亦未繘井，羸其瓶，凶。','井卦象征水井，改变城邑不改变水井，没有丧失没有获得，往来井然有序。将要到达，还没有打到井水，打破了瓶子，凶险。'),(378,48,'大象',NULL,'木上有水，井；君子以劳民劝相。','木上有水象征水井，君子应当慰劳民众劝勉互助。'),(379,48,'爻辞',1,'初六：井泥不食，旧井无禽。','井泥不能食用，旧井没有禽兽。'),(380,48,'爻辞',2,'九二：井谷射鲋，瓮敝漏。','井谷射鲋鱼，瓮破漏水。'),(381,48,'爻辞',3,'九三：井渫不食，为我心恻，可用汲，王明，并受其福。','井清洁不食用，为我心悲伤，可以汲水，君王明察，一起受其福。'),(382,48,'爻辞',4,'六四：井甃，无咎。','井砌砖，没有灾祸。'),(383,48,'爻辞',5,'九五：井冽，寒泉食。','井清冽，寒泉可食用。'),(384,48,'爻辞',6,'上六：井收勿幕，有孚元吉。','井收成不要覆盖，有诚信大吉大利。'),(385,49,'卦辞',NULL,'革：己日乃孚，元亨利贞，悔亡。','革卦象征变革，己日才有诚信，元始亨通利于守正，悔恨消亡。'),(386,49,'大象',NULL,'泽中有火，革；君子以治历明时。','泽中有火象征变革，君子应当治理历法明确时令。'),(387,49,'爻辞',1,'初九：巩用黄牛之革。','巩固用黄牛皮。'),(388,49,'爻辞',2,'六二：己日乃革之，征吉，无咎。','己日才变革，出征吉祥，没有灾祸。'),(389,49,'爻辞',3,'九三：征凶，贞厉，革言三就，有孚。','出征凶险，守正危险，变革之言三次成就，有诚信。'),(390,49,'爻辞',4,'九四：悔亡，有孚改命，吉。','悔恨消亡，有诚信改变命令，吉祥。'),(391,49,'爻辞',5,'九五：大人虎变，未占有孚。','大人如虎变化，不用占卜有诚信。'),(392,49,'爻辞',6,'上六：君子豹变，小人革面，征凶，居贞吉。','君子如豹变化，小人改变面目，出征凶险，安居守正吉祥。'),(393,50,'卦辞',NULL,'鼎：元吉，亨。','鼎卦象征鼎器，大吉大利，亨通。'),(394,50,'大象',NULL,'木上有火，鼎；君子以正位凝命。','木上有火象征鼎器，君子应当端正位置凝聚天命。'),(395,50,'爻辞',1,'初六：鼎颠趾，利出否，得妾以其子，无咎。','鼎颠倒脚，利于倒出渣滓，得妾因为其子，没有灾祸。'),(396,50,'爻辞',2,'九二：鼎有实，我仇有疾，不我能即，吉。','鼎有食物，我的仇人有疾病，不能接近我，吉祥。'),(397,50,'爻辞',3,'九三：鼎耳革，其行塞，雉膏不食，方雨亏悔，终吉。','鼎耳变革，其行阻塞，野鸡膏不能食用，正下雨减少悔恨，最终吉祥。'),(398,50,'爻辞',4,'九四：鼎折足，覆公餗，其形渥，凶。','鼎折断脚，倾覆公侯的食物，其形沾污，凶险。'),(399,50,'爻辞',5,'六五：鼎黄耳金铉，利贞。','鼎黄色耳金色铉，利于守正。'),(400,50,'爻辞',6,'上九：鼎玉铉，大吉，无不利。','鼎玉铉，大吉大利，无所不利。'),(401,51,'卦辞',NULL,'震：亨。震来虩虩，笑言哑哑。震惊百里，不丧匕鬯。','震卦象征震动，亨通。震动来临恐惧战栗，笑言哑哑。震惊百里，不丧失匕鬯。'),(402,51,'大象',NULL,'洊雷震；君子以恐惧修省。','重雷象征震动，君子应当恐惧修省。'),(403,51,'爻辞',1,'初九：震来虩虩，后笑言哑哑，吉。','震动来临恐惧战栗，后来笑言哑哑，吉祥。'),(404,51,'爻辞',2,'六二：震来厉，亿丧贝，跻于九陵，勿逐，七日得。','震动来临危险，估计丧失贝，登上九陵，不要追逐，七日得到。'),(405,51,'爻辞',3,'六三：震苏苏，震行无眚。','震动苏醒，震动行动没有灾祸。'),(406,51,'爻辞',4,'九四：震遂泥。','震动于是陷入泥中。'),(407,51,'爻辞',5,'六五：震往来厉，亿无丧，有事。','震动往来危险，估计没有丧失，有事。'),(408,51,'爻辞',6,'上六：震索索，视矍矍，征凶。震不于其躬，于其邻，无咎。婚媾有言。','震动索索，视矍矍，出征凶险。震动不在其身，在其邻居，没有灾祸。婚姻有言语。'),(409,52,'卦辞',NULL,'艮：艮其背，不获其身，行其庭，不见其人，无咎。','艮卦象征止息，止息于背部，不获得其身，行走于庭院，不见其人，没有灾祸。'),(410,52,'大象',NULL,'兼山艮；君子以思不出其位。','两山象征止息，君子应当思虑不超出其位。'),(411,52,'爻辞',1,'初六：艮其趾，无咎，利永贞。','止息于脚趾，没有灾祸，利于永久守正。'),(412,52,'爻辞',2,'六二：艮其腓，不拯其随，其心不快。','止息于小腿，不拯救其随从，其心不快。'),(413,52,'爻辞',3,'九三：艮其限，列其夤，厉薰心。','止息于腰部，裂其脊肉，危险熏心。'),(414,52,'爻辞',4,'六四：艮其身，无咎。','止息于身体，没有灾祸。'),(415,52,'爻辞',5,'六五：艮其辅，言有序，悔亡。','止息于牙床，言语有序，悔恨消亡。'),(416,52,'爻辞',6,'上九：敦艮，吉。','敦厚止息，吉祥。'),(417,53,'卦辞',NULL,'渐：女归吉，利贞。','渐卦象征渐进，女子出嫁吉祥，利于守正。'),(418,53,'大象',NULL,'山上有木，渐；君子以居贤德善俗。','山上有木象征渐进，君子应当居于贤德善化风俗。'),(419,53,'爻辞',1,'初六：鸿渐于干，小子厉，有言，无咎。','鸿雁渐进于水边，小子危险，有言语，没有灾祸。'),(420,53,'爻辞',2,'六二：鸿渐于磐，饮食衎衎，吉。','鸿雁渐进于磐石，饮食安乐，吉祥。'),(421,53,'爻辞',3,'九三：鸿渐于陆，夫征不复，妇孕不育，凶；利御寇。','鸿雁渐进于陆地，丈夫出征不回，妇人怀孕不育，凶险；利于防御盗寇。'),(422,53,'爻辞',4,'六四：鸿渐于木，或得其桷，无咎。','鸿雁渐进于树木，或许得到其椽木，没有灾祸。'),(423,53,'爻辞',5,'九五：鸿渐于陵，妇三岁不孕，终莫之胜，吉。','鸿雁渐进于丘陵，妇人三年不孕，最终没有人能胜，吉祥。'),(424,53,'爻辞',6,'上九：鸿渐于陆，其羽可用为仪，吉。','鸿雁渐进于陆地，其羽毛可用为仪式，吉祥。'),(425,54,'卦辞',NULL,'归妹：征凶，无攸利。','归妹卦象征嫁女，出征凶险，没有什么利益。'),(426,54,'大象',NULL,'泽上有雷，归妹；君子以永终知敝。','泽上有雷象征嫁女，君子应当永远知道终结和弊端。'),(427,54,'爻辞',1,'初九：归妹以娣，跛能履，征吉。','嫁女以妹，跛脚能走，出征吉祥。'),(428,54,'爻辞',2,'九二：眇能视，利幽人之贞。','独眼能看，利于隐士的守正。'),(429,54,'爻辞',3,'六三：归妹以须，反归以娣。','嫁女以等待，返回以妹。'),(430,54,'爻辞',4,'九四：归妹愆期，迟归有时。','嫁女延期，迟归有时。'),(431,54,'爻辞',5,'六五：帝乙归妹，其君之袂，不如其娣之袂良，月几望，吉。','帝乙嫁女，其君的衣袖，不如其妹的衣袖好，月亮将近满月，吉祥。'),(432,54,'爻辞',6,'上六：女承筐无实，士刲羊无血，无攸利。','女子承筐没有果实，士人杀羊没有血，没有什么利益。'),(433,55,'卦辞',NULL,'丰：亨，王假之，勿忧，宜日中。','丰卦象征丰盛，亨通，君王到达，不要忧虑，宜于日中。'),(434,55,'大象',NULL,'雷电皆至，丰；君子以折狱致刑。','雷电都到来象征丰盛，君子应当断狱施刑。'),(435,55,'爻辞',1,'初九：遇其配主，虽旬无咎，往有尚。','遇到其配主，虽然十天没有灾祸，前往有嘉尚。'),(436,55,'爻辞',2,'六二：丰其蔀，日中见斗，往得疑疾，有孚发若，吉。','丰盛其遮蔽，日中见北斗，前往得到疑虑疾病，有诚信发扬，吉祥。'),(437,55,'爻辞',3,'九三：丰其沛，日中见沬，折其右肱，无咎。','丰盛其旗帜，日中见小星，折断其右臂，没有灾祸。'),(438,55,'爻辞',4,'九四：丰其蔀，日中见斗，遇其夷主，吉。','丰盛其遮蔽，日中见北斗，遇到其平等主人，吉祥。'),(439,55,'爻辞',5,'六五：来章，有庆誉，吉。','来美德，有庆贺荣誉，吉祥。'),(440,55,'爻辞',6,'上六：丰其屋，蔀其家，窥其户，阒其无人，三岁不觌，凶。','丰盛其屋，遮蔽其家，窥视其门户，寂静无人，三年不见，凶险。'),(441,56,'卦辞',NULL,'旅：小亨，旅贞吉。','旅卦象征旅行，小亨通，旅行守正吉祥。'),(442,56,'大象',NULL,'山上有火，旅；君子以明慎用刑，而不留狱。','山上有火象征旅行，君子应当明察慎用刑罚，而不滞留狱讼。'),(443,56,'爻辞',1,'初六：旅琐琐，斯其所取灾。','旅行琐碎，这是其所取的灾祸。'),(444,56,'爻辞',2,'六二：旅即次，怀其资，得童仆贞。','旅行到达住所，怀揣其资财，得到童仆守正。'),(445,56,'爻辞',3,'九三：旅焚其次，丧其童仆，贞厉。','旅行焚烧其住所，丧失其童仆，守正危险。'),(446,56,'爻辞',4,'九四：旅于处，得其资斧，我心不快。','旅行于处所，得到其资财斧头，我心不快。'),(447,56,'爻辞',5,'六五：射雉一矢亡，终以誉命。','射野鸡一箭丧失，最终以荣誉命令。'),(448,56,'爻辞',6,'上九：鸟焚其巢，旅人先笑后号咷，丧牛于易，凶。','鸟焚烧其巢，旅人先笑后号哭，在易地丧失牛，凶险。'),(449,57,'卦辞',NULL,'巽：小亨，利有攸往，利见大人。','巽卦象征顺从，小亨通，利于有所往，利于拜见大人。'),(450,57,'大象',NULL,'随风巽；君子以申命行事。','随风象征顺从，君子应当申明命令行事。'),(451,57,'爻辞',1,'初六：进退，利武人之贞。','进退，利于武人的守正。'),(452,57,'爻辞',2,'九二：巽在床下，用史巫纷若，吉无咎。','顺从在床下，用史巫纷纷，吉祥没有灾祸。'),(453,57,'爻辞',3,'九三：频巽，吝。','频繁顺从，有悔。'),(454,57,'爻辞',4,'六四：悔亡，田获三品。','悔恨消亡，田猎获得三品。'),(455,57,'爻辞',5,'九五：贞吉悔亡，无不利。无初有终，先庚三日，后庚三日，吉。','守正吉祥悔恨消亡，无所不利。没有开始有结局，庚日前三天，庚日后三天，吉祥。'),(456,57,'爻辞',6,'上九：巽在床下，丧其资斧，贞凶。','顺从在床下，丧失其资财斧头，守正凶险。'),(457,58,'卦辞',NULL,'兑：亨，利贞。','兑卦象征喜悦，亨通，利于守正。'),(458,58,'大象',NULL,'丽泽兑；君子以朋友讲习。','两泽相连象征喜悦，君子应当与朋友讲习。'),(459,58,'爻辞',1,'初九：和兑，吉。','和悦喜悦，吉祥。'),(460,58,'爻辞',2,'九二：孚兑，吉，悔亡。','诚信喜悦，吉祥，悔恨消亡。'),(461,58,'爻辞',3,'六三：来兑，凶。','来喜悦，凶险。'),(462,58,'爻辞',4,'九四：商兑未宁，介疾有喜。','商量喜悦未安宁，介于疾病有喜。'),(463,58,'爻辞',5,'九五：孚于剥，有厉。','诚信于剥落，有危险。'),(464,58,'爻辞',6,'上六：引兑。','引导喜悦。'),(465,59,'卦辞',NULL,'涣：亨。王假有庙，利涉大川，利贞。','涣卦象征涣散，亨通。君王到达宗庙，利于渡过大河，利于守正。'),(466,59,'大象',NULL,'风行水上，涣；先王以享于帝立庙。','风行于水上象征涣散，先王因此祭享上帝建立宗庙。'),(467,59,'爻辞',1,'初六：用拯马壮，吉。','用壮马拯救，吉祥。'),(468,59,'爻辞',2,'九二：涣奔其机，悔亡。','涣散奔向其几案，悔恨消亡。'),(469,59,'爻辞',3,'六三：涣其躬，无悔。','涣散其身，没有悔恨。'),(470,59,'爻辞',4,'六四：涣其群，元吉。涣有丘，匪夷所思。','涣散其群，大吉大利。涣散有丘，不是平常所思。'),(471,59,'爻辞',5,'九五：涣汗其大号，涣王居，无咎。','涣散汗水其大号令，涣散君王居所，没有灾祸。'),(472,59,'爻辞',6,'上九：涣其血，去逖出，无咎。','涣散其血，去除远离，没有灾祸。'),(473,60,'卦辞',NULL,'节：亨。苦节不可贞。','节卦象征节制，亨通。苦涩的节制不可守正。'),(474,60,'大象',NULL,'泽上有水，节；君子以制数度，议德行。','泽上有水象征节制，君子应当制定数度，议论德行。'),(475,60,'爻辞',1,'初九：不出户庭，无咎。','不出门庭，没有灾祸。'),(476,60,'爻辞',2,'九二：不出门庭，凶。','不出门庭，凶险。'),(477,60,'爻辞',3,'六三：不节若，则嗟若，无咎。','不节制，则叹息，没有灾祸。'),(478,60,'爻辞',4,'六四：安节，亨。','安于节制，亨通。'),(479,60,'爻辞',5,'九五：甘节，吉；往有尚。','甘美节制，吉祥；前往有嘉尚。'),(480,60,'爻辞',6,'上六：苦节，贞凶，悔亡。','苦涩节制，守正凶险，悔恨消亡。'),(481,61,'卦辞',NULL,'中孚：豚鱼吉，利涉大川，利贞。','中孚卦象征诚信，豚鱼吉祥，利于渡过大河，利于守正。'),(482,61,'大象',NULL,'泽上有风，中孚；君子以议狱缓死。','泽上有风象征诚信，君子应当议论狱讼缓和死刑。'),(483,61,'爻辞',1,'初九：虞吉，有它不燕。','安虞吉祥，有其他不安。'),(484,61,'爻辞',2,'九二：鸣鹤在阴，其子和之。我有好爵，吾与尔靡之。','鸣叫的鹤在阴处，其子和应。我有好酒，我与你共享。'),(485,61,'爻辞',3,'六三：得敌，或鼓或罢，或泣或歌。','得到敌人，或击鼓或停止，或哭泣或歌唱。'),(486,61,'爻辞',4,'六四：月几望，马匹亡，无咎。','月亮将近满月，马匹丧失，没有灾祸。'),(487,61,'爻辞',5,'九五：有孚挛如，无咎。','有诚信紧密相连，没有灾祸。'),(488,61,'爻辞',6,'上九：翰音登于天，贞凶。','鸡鸣声登于天，守正凶险。'),(489,62,'卦辞',NULL,'小过：亨，利贞，可小事，不可大事。飞鸟遗之音，不宜上宜下，大吉。','小过卦象征小过，亨通，利于守正，可以做小事，不可以做大事。飞鸟遗留声音，不宜向上宜于向下，大吉大利。'),(490,62,'大象',NULL,'山上有雷，小过；君子以行过乎恭，丧过乎哀，用过乎俭。','山上有雷象征小过，君子应当行为过于恭敬，丧事过于哀伤，用度过于节俭。'),(491,62,'爻辞',1,'初六：飞鸟以凶。','飞鸟以凶险。'),(492,62,'爻辞',2,'六二：过其祖，遇其妣；不及其君，遇其臣；无咎。','过其祖父，遇其祖母；不及其君，遇其臣；没有灾祸。'),(493,62,'爻辞',3,'九三：弗过防之，从或戕之，凶。','不过度防备，随从或许伤害，凶险。'),(494,62,'爻辞',4,'九四：无咎，弗过遇之。往厉必戒，勿用永贞。','没有灾祸，不过度遇到。前往危险必须戒备，不要用永久守正。'),(495,62,'爻辞',5,'六五：密云不雨，自我西郊，公弋取彼在穴。','密云不下雨，从我的西郊，公侯射取那在穴中的。'),(496,62,'爻辞',6,'上六：弗遇过之，飞鸟离之，凶，是谓灾眚。','不遇过度，飞鸟离开，凶险，这叫灾祸。'),(497,63,'卦辞',NULL,'既济：亨小，利贞，初吉终乱。','既济卦象征已经完成，小亨通，利于守正，开始吉祥最终混乱。'),(498,63,'大象',NULL,'水在火上，既济；君子以思患而预防之。','水在火上象征已经完成，君子应当思虑祸患而预防。'),(499,63,'爻辞',1,'初九：曳其轮，濡其尾，无咎。','拖曳其车轮，沾湿其尾巴，没有灾祸。'),(500,63,'爻辞',2,'六二：妇丧其茀，勿逐，七日得。','妇人丧失其车帷，不要追逐，七日得到。'),(501,63,'爻辞',3,'九三：高宗伐鬼方，三年克之，小人勿用。','高宗征伐鬼方，三年克服，小人不要任用。'),(502,63,'爻辞',4,'六四：繻有衣袽，终日戒。','有破旧衣服，整天戒备。'),(503,63,'爻辞',5,'九五：东邻杀牛，不如西邻之禴祭，实受其福。','东邻杀牛，不如西邻的禴祭，实际受其福。'),(504,63,'爻辞',6,'上六：濡其首，厉。','沾湿其头，危险。'),(505,64,'卦辞',NULL,'未济：亨，小狐汔济，濡其尾，无攸利。','未济卦象征尚未完成，亨通，小狐狸将要渡河，沾湿了尾巴，没有什么利益。'),(506,64,'大象',NULL,'火在水上，未济；君子以慎辨物居方。','火在水上象征尚未完成，君子应当谨慎辨别事物安居方位。'),(507,64,'爻辞',1,'初六：濡其尾，吝。','沾湿其尾巴，有悔。'),(508,64,'爻辞',2,'九二：曳其轮，贞吉。','拖曳其车轮，守正吉祥。'),(509,64,'爻辞',3,'六三：未济，征凶，利涉大川。','尚未完成，出征凶险，利于渡过大河。'),(510,64,'爻辞',4,'九四：贞吉，悔亡，震用伐鬼方，三年有赏于大国。','守正吉祥，悔恨消亡，震动用来征伐鬼方，三年有赏于大国。'),(511,64,'爻辞',5,'六五：贞吉，无悔，君子之光，有孚，吉。','守正吉祥，没有悔恨，君子的光辉，有诚信，吉祥。'),(512,64,'爻辞',6,'上九：有孚于饮酒，无咎，濡其首，有孚失是。','有诚信于饮酒，没有灾祸，沾湿其头，有诚信失去正道。');
/*!40000 ALTER TABLE `base_hexagram_text` ENABLE KEYS */;
