DROP TABLE IF EXISTS `base_yao_rule`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `base_yao_rule` (
  `gua` char(1) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '单卦（乾坎艮震巽离坤兑）',
  `gua_nature` char(1) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '单卦五行',
  `is_upper` tinyint(1) NOT NULL COMMENT '是否为上卦（1上卦，0下卦）',
  `position_in_hexagram` tinyint NOT NULL COMMENT '在重卦中位置（1-3下卦，4-6上卦）',
  `stem` char(1) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '纳干',
  `branch` char(1) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '纳支',
  `branch_order` tinyint NOT NULL COMMENT '地支序（子1丑2...亥12）',
  PRIMARY KEY (`gua`,`is_upper`,`position_in_hexagram`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='单卦纳甲规则表（静态，用于程序化装卦）';
/*!40101 SET character_set_client = @saved_cs_client */;

