DROP TABLE IF EXISTS `tb_achievement`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tb_achievement` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `achievement_code` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '成就代码（唯一）',
  `achievement_name` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '成就名称',
  `achievement_description` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '成就描述',
  `achievement_type` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '成就类型：divination-占卜，favorite-收藏，invite-邀请，checkin-签到，points-积分',
  `points_reward` int NOT NULL COMMENT '积分奖励',
  `icon_url` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '成就图标URL',
  `is_active` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否启用：0-禁用，1-启用',
  `sort_order` int NOT NULL DEFAULT '0' COMMENT '排序顺序',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_achievement_code` (`achievement_code`),
  KEY `idx_achievement_type` (`achievement_type`),
  KEY `idx_is_active` (`is_active`)
) ENGINE=InnoDB AUTO_INCREMENT=12 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='成就定义表';
/*!40101 SET character_set_client = @saved_cs_client */;

