--
-- Table structure for table `tb_bazi_compatibility`
--

DROP TABLE IF EXISTS `tb_bazi_compatibility`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tb_bazi_compatibility` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `user_id` bigint NOT NULL COMMENT '用户ID',
  `partner_type` varchar(20) NOT NULL COMMENT '合盘对象类型：friend, lover, spouse等',
  `partner_name` varchar(100) DEFAULT NULL COMMENT '合盘对象姓名',
  `user_bazi` varchar(50) NOT NULL COMMENT '用户八字',
  `partner_bazi` varchar(50) NOT NULL COMMENT '合盘对象八字',
  `compatibility_score` int DEFAULT NULL COMMENT '契合度评分：0-100',
  `compatibility_data` json DEFAULT NULL COMMENT '契合度详细数据',
  `visualization_data` json DEFAULT NULL COMMENT '可视化数据',
  `ai_analysis` text COMMENT 'AI分析',
  `suggestion` text COMMENT '相处建议',
  `is_shared` tinyint DEFAULT '0' COMMENT '是否分享：0否，1是',
  `share_url` varchar(500) DEFAULT NULL COMMENT '分享链接',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  KEY `idx_user` (`user_id`),
  KEY `idx_shared` (`is_shared`),
  CONSTRAINT `fk_compatibility_user` FOREIGN KEY (`user_id`) REFERENCES `tb_user` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='八字合盘记录表';
