DROP TABLE IF EXISTS `tb_bazi_interpretation`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tb_bazi_interpretation` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `god_type` varchar(20) NOT NULL COMMENT '十神类型：正财、偏财、正官、七杀、正印、偏印、比肩、劫财、食神、伤官',
  `ganzhi_position` varchar(20) NOT NULL COMMENT '干支位置：年干、年支、月干、月支、日支、时干、时支',
  `basic_def` mediumtext NOT NULL COMMENT '十神基础定义+该位置的命理核心含义【详细版】',
  `main_content` mediumtext NOT NULL COMMENT '核心解读：分性格、情感、职业 三大维度详细解读',
  `support_content` mediumtext COMMENT '生扶状态：得五行生助时的详细影响（财运/情感/事业）',
  `restrict_content` mediumtext COMMENT '制约状态：被五行克泄时的详细影响（财运/情感/事业）',
  `gender_diff` mediumtext COMMENT '男女差异化解读：分男性/女性不同命理表现，无差异则为NULL',
  `tag` varchar(100) DEFAULT NULL COMMENT '关联标签，英文分号分隔：财运;情感;生活品质;职场',
  `help_count` int unsigned DEFAULT '0' COMMENT '有帮助 点击数，适配前端交互',
  `unhelp_count` int unsigned DEFAULT '0' COMMENT '无帮助 点击数，适配前端交互',
  `comment_count` int unsigned DEFAULT '0' COMMENT '评论数量，适配前端展示',
  `sort` tinyint unsigned DEFAULT '10' COMMENT '排序权重，数字越小越靠前',
  `status` tinyint unsigned DEFAULT '1' COMMENT '状态 1-启用 0-禁用',
  PRIMARY KEY (`id`),
  UNIQUE KEY `idx_god_position` (`god_type`,`ganzhi_position`),
  KEY `idx_tag` (`tag`)
) ENGINE=InnoDB AUTO_INCREMENT=29 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='八字命理-十神×干支位置 完整解读内容库';
/*!40101 SET character_set_client = @saved_cs_client */;

