INSERT INTO `tb_content` VALUES (1,'bazi_shishen_intro','八字十神对应性格','了解十神如何影响你的性格特点','article','beginner','shishen',NULL,'十神是八字命理中的重要概念，包括正官、偏官、正财、偏财、正印、偏印、比肩、劫财、食神、伤官。每个十神都对应不同的性格特征...',NULL,NULL,NULL,1,1,0,0,1,'2026-01-11 01:08:40','2026-01-11 01:08:40'),(2,'zodiac_compatibility','生肖相合禁忌','哪些生肖最相配，哪些需要避免','article','beginner','zodiac',NULL,'生肖相合是传统命理中的重要参考，了解生肖之间的相合相冲关系，有助于改善人际关系...',NULL,NULL,NULL,1,1,0,0,2,'2026-01-11 01:08:40','2026-01-11 01:08:40'),(3,'dayun_interpretation','大运流年解读技巧','深入理解大运流年的变化规律','course','intermediate','dayun',NULL,'大运流年是八字命理中的核心概念，掌握解读技巧可以帮助你更好地把握人生机遇...',NULL,NULL,NULL,0,1,0,0,1,'2026-01-11 01:08:40','2026-01-11 01:08:40'),(4,'bazi_tiaohou','八字调候原理','了解五行调候的深层逻辑','course','intermediate','wuxing',NULL,'调候是八字命理中的重要技法，通过分析五行的旺衰和调候需求，可以找到改善运势的方法...',NULL,NULL,NULL,0,1,0,0,2,'2026-01-11 01:08:40','2026-01-11 01:08:40'),(5,'meditation_wood_deficiency','八字缺木者的静心冥想','针对五行缺木的定制化冥想课程','course','advanced','emotion',NULL,'五行缺木的人往往缺乏生机和活力，通过特定的冥想练习可以补充木行能量，提升内在力量...',NULL,NULL,NULL,0,1,0,0,1,'2026-01-11 01:08:40','2026-01-11 01:08:40'),(6,'emotion_cooling_fire','八字火旺者的情绪降温指南','帮助火旺者平衡情绪，保持内心平静','article','advanced','emotion',NULL,'五行火旺的人容易情绪激动，需要通过特定的方法调节情绪，保持内心的平衡...',NULL,NULL,NULL,0,1,0,0,2,'2026-01-11 01:08:40','2026-01-11 01:08:40');
