--
-- Table structure for table `tb_daily_lucky`
--

DROP TABLE IF EXISTS `tb_daily_lucky`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tb_daily_lucky` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `lucky_date` date NOT NULL COMMENT '日期',
  `lucky_number` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '幸运数字',
  `lucky_color` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '幸运颜色',
  `lucky_constellation` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '幸运星座',
  `lucky_food` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '幸运食物',
  `suitable_actions` text COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '宜：适合做的事情（多个用空格或逗号分隔）',
  `unsuitable_actions` text COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '忌：不适合做的事情（多个用空格或逗号分隔）',
  `description` text COLLATE utf8mb4_unicode_ci COMMENT '描述或备注',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_lucky_date` (`lucky_date`),
  KEY `idx_lucky_date` (`lucky_date`)
) ENGINE=InnoDB AUTO_INCREMENT=61 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='每日幸运表';
/*!40101 SET character_set_client = @saved_cs_client */;

