  KEY `idx_referral_code` (`referral_code`),
  KEY `idx_invite_status` (`invite_status`),
  KEY `idx_create_time` (`create_time`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='邀请记录表';
