  `card_type` enum('MAJOR_ARCANA','MINOR_ARCANA') COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '牌类型（大阿卡纳/小阿卡纳）',
  `suit` enum('NONE','WANDS','CUPS','SWORDS','PENTACLES') COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '花色（无/权杖/圣杯/宝剑/星币）',
  `number` tinyint unsigned DEFAULT NULL COMMENT '数字（1-14，大牌为0）',
