  `keyword_up` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '正位关键词',
  `keyword_rev` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '逆位关键词',
  `meaning_up` text COLLATE utf8mb4_unicode_ci COMMENT '正位含义',
  `meaning_rev` text COLLATE utf8mb4_unicode_ci COMMENT '逆位含义',
  `description` text COLLATE utf8mb4_unicode_ci COMMENT '牌面描述',
  `interpretation_up` text COLLATE utf8mb4_unicode_ci COMMENT '正位详细解读',
  `interpretation_rev` text COLLATE utf8mb4_unicode_ci COMMENT '逆位详细解读',
  `love_up` text COLLATE utf8mb4_unicode_ci COMMENT '正位爱情含义',
  `love_rev` text COLLATE utf8mb4_unicode_ci COMMENT '逆位爱情含义',
  `career_up` text COLLATE utf8mb4_unicode_ci COMMENT '正位事业含义',
  `career_rev` text COLLATE utf8mb4_unicode_ci COMMENT '逆位事业含义',
  `wealth_up` text COLLATE utf8mb4_unicode_ci COMMENT '正位财运含义',
  `wealth_rev` text COLLATE utf8mb4_unicode_ci COMMENT '逆位财运含义',
  `health_up` text COLLATE utf8mb4_unicode_ci COMMENT '正位健康含义',
  `health_rev` text COLLATE utf8mb4_unicode_ci COMMENT '逆位健康含义',
  `advice_up` text COLLATE utf8mb4_unicode_ci COMMENT '正位建议',
  `advice_rev` text COLLATE utf8mb4_unicode_ci COMMENT '逆位建议',
  `image_url` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '牌面图片URL',
  `sort_order` tinyint unsigned NOT NULL DEFAULT '0' COMMENT '排序顺序',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
